        self.taken = domain.taken
        self.takenAt = domain.takenAt
        self.note = domain.note
        self.createdAt = domain.createdAt
        self.updatedAt = domain.updatedAt
    }

    func toDomain() -> ProtocolAdherence {
        ProtocolAdherence(
            id: id,
            protocolID: protocolID,
            dateKey: dateKey,
            taken: taken,
            takenAt: takenAt,
            note: note,
            createdAt: createdAt,
            updatedAt: updatedAt
        )
