    var isImportedPlaceholder: Bool
    var archivedAt: Date?
    /// Encrypted JSON blob containing `formulaText` + `components` + timestamps.
    var bodyData: Data
    var createdAt: Date
    var updatedAt: Date

    init(
        id: UUID,
        displayLabel: String,
        ordinalIndex: Int,
