212	            limitedDescriptor.fetchLimit = max(0, limit)
213	        }
214	
215	        let alerts = try modelContext.fetch(limitedDescriptor).map { $0.toDomain() }
216	        let filteredAlerts = alerts.filter { alert in
217	            guard let fromSleepDateKey else { return true }
218	            guard let sleepDateKey = alert.sleepDateKey else { return false }
219	            return sleepDateKey >= fromSleepDateKey
220	        }
221	
222	        guard let limit else { return filteredAlerts }
223	        return Array(filteredAlerts.prefix(max(0, limit)))
224	    }
