523	    // MARK: - Protocol Formula Tracking
524	
525	    func saveFormulaVersion(_ version: ProtocolFormulaVersion) async throws {
526	        let id = version.id
527	        let descriptor = FetchDescriptor<StoredProtocolFormulaVersion>(
528	            predicate: #Predicate { row in row.id == id }
529	        )
530	        let existing = try modelContext.fetch(descriptor).first
531	
532	        // Compute ordinal index — count of existing rows with an earlier `shippedOn`, or
533	        // keep the existing index if the row already exists.
534	        let ordinalIndex: Int
535	        if let existing {
536	            ordinalIndex = existing.ordinalIndex
537	        } else {
538	            let allDescriptor = FetchDescriptor<StoredProtocolFormulaVersion>(
539	                sortBy: [SortDescriptor(\.shippedOn)]
540	            )
541	            let all = try modelContext.fetch(allDescriptor)
542	            ordinalIndex = all.filter { $0.shippedOn <= version.shippedOn }.count + 1
543	        }
544	
545	        // Immutability rule: if this version has any logs and `formulaText`/`components`
546	        // changed, reject the write — UNLESS the existing row is still an imported
547	        // placeholder with empty text and the incoming text is non-empty (the one
548	        // permitted backfill, which atomically clears the placeholder flag).
549	        var versionToWrite = version
550	        if let existing {
551	            let logCount = try modelContext.fetchCount(FetchDescriptor<StoredProtocolNightLog>(
552	                predicate: #Predicate { log in log.versionIDString == id.uuidString }
553	            ))
554	            if logCount > 0 {
555	                let existingDomain = try existing.toDomain(ordinalLabel: "")
556	                let textChanged = existingDomain.formulaText != version.formulaText
557	                let componentsChanged = existingDomain.components != version.components
558	                let placeholderBackfill = existing.isImportedPlaceholder &&
559	                    existingDomain.formulaText.isEmpty &&
560	                    !version.formulaText.isEmpty
561	                if (textChanged || componentsChanged) && !placeholderBackfill {
562	                    throw ProtocolFormulaRepositoryError.formulaTextLocked(versionID: id)
563	                }
564	                if placeholderBackfill {
565	                    versionToWrite.isImportedPlaceholder = false
566	                }
567	            }
568	        }
569	
570	        // Active-singleton enforcement: clear `isActive` on any other row when this row is active.
571	        if versionToWrite.isActive {
572	            let othersDescriptor = FetchDescriptor<StoredProtocolFormulaVersion>(
573	                predicate: #Predicate { row in row.id != id && row.isActive }
574	            )
575	            for other in try modelContext.fetch(othersDescriptor) {
576	                other.isActive = false
577	                other.updatedAt = Date()
578	            }
579	        }
580	
581	        if let existing {
582	            modelContext.delete(existing)
583	        }
584	        let stored = try StoredProtocolFormulaVersion(domain: versionToWrite, ordinalIndex: ordinalIndex)
585	        modelContext.insert(stored)
586	        try modelContext.save()
587	    }
