776	    func migrateToEncryptedStorage() async throws {
777	        // Sleep sessions — re-encode all JSON blob fields via PersistenceJSON (which now encrypts).
778	        for session in try modelContext.fetch(FetchDescriptor<StoredSleepSession>()) {
779	            await Task.yield()
780	            guard let domain = try? session.toDomain() else { continue }
781	            session.qualityScoreData = try PersistenceJSON.encode(domain.qualityScore)
782	            session.stagesData = try PersistenceJSON.encode(domain.stages)
783	            session.sourcesData = try PersistenceJSON.encode(domain.sources)
784	            if let biometrics = domain.biometrics {
785	                session.biometricsData = try PersistenceJSON.encode(biometrics)
786	            }
787	        }
788	
789	        // Sleep Mode blobs.
790	        for settings in try modelContext.fetch(FetchDescriptor<StoredSleepModeSettings>()) {
791	            guard let domain = try? settings.toDomain() else { continue }
792	            settings.settingsData = try PersistenceJSON.encode(domain)
793	        }
794	        for schedule in try modelContext.fetch(FetchDescriptor<StoredSleepModeSchedule>()) {
795	            guard let domain = try? schedule.toDomain() else { continue }
796	            schedule.scheduleData = try PersistenceJSON.encode(domain)
797	        }
798	        for session in try modelContext.fetch(FetchDescriptor<StoredSleepModeSession>()) {
799	            await Task.yield()
800	            guard let domain = try? session.toDomain() else { continue }
801	            session.sessionData = try PersistenceJSON.encode(domain)
802	        }
803	
804	        // Nightly biometric summaries.
805	        for summary in try modelContext.fetch(FetchDescriptor<StoredNightlyBiometricSummary>()) {
806	            await Task.yield()
807	            guard let domain = try? summary.toDomain() else { continue }
808	            summary.samplesData = try PersistenceJSON.encode(domain.samples)
809	        }
810	
811	        // User profile — onboarding assessment answers.
812	        for profile in try modelContext.fetch(FetchDescriptor<StoredUserProfile>()) {
813	            guard
814	                let raw = profile.sleepAssessmentAnswersData,
815	                let answers = try? PersistenceJSON.decode([SleepAssessmentAnswer].self, from: raw)
816	            else { continue }
817	            profile.sleepAssessmentAnswersData = try PersistenceJSON.encode(answers)
818	        }
819	
820	        // Protocol Formula blobs — re-encode through the convenience initializers so the
821	        // bytes are routed through `PersistenceJSON.encode` (which now encrypts). The
822	        // freshly-constructed @Model instances are never inserted into the context;
823	        // they're only used as a transport for the re-encoded bodyData bytes.
824	        for row in try modelContext.fetch(FetchDescriptor<StoredProtocolFormulaVersion>()) {
825	            guard let domain = try? row.toDomain(ordinalLabel: "") else { continue }
826	            let rewritten = try StoredProtocolFormulaVersion(domain: domain, ordinalIndex: row.ordinalIndex)
827	            row.bodyData = rewritten.bodyData
828	        }
829	        for row in try modelContext.fetch(FetchDescriptor<StoredProtocolNightLog>()) {
830	            await Task.yield()
831	            guard let domain = try? row.toDomain() else { continue }
832	            let rewritten = try StoredProtocolNightLog(domain: domain)
833	            row.bodyData = rewritten.bodyData
834	        }
835	        for row in try modelContext.fetch(FetchDescriptor<StoredProtocolBaselineSnapshot>()) {
836	            guard let domain = try? row.toDomain() else { continue }
837	            let rewritten = try StoredProtocolBaselineSnapshot(domain: domain)
838	            row.bodyData = rewritten.bodyData
839	        }
840	
841	        try modelContext.save()
842	    }
843	
844	    func fetchDataInventory() async throws -> LocalDataInventory {
845	        let sessionDescriptor = FetchDescriptor<StoredSleepSession>(
846	            sortBy: [SortDescriptor(\.startDate)]
847	        )
848	        let sessions = try modelContext.fetch(sessionDescriptor)
849	
850	        var contextDescriptor = FetchDescriptor<StoredSleepContextEntry>(
851	            sortBy: [SortDescriptor(\.updatedAt, order: .reverse)]
852	        )
853	        contextDescriptor.fetchLimit = 1
854	        let latestContextEntry = try modelContext.fetch(contextDescriptor).first
855	        let contextCount = try modelContext.fetchCount(FetchDescriptor<StoredSleepContextEntry>())
856	        var sleepModeSessionDescriptor = FetchDescriptor<StoredSleepModeSession>(
857	            sortBy: [SortDescriptor(\.startedAt, order: .reverse)]
858	        )
859	        sleepModeSessionDescriptor.fetchLimit = 1
860	        let latestSleepModeSession = try modelContext.fetch(sleepModeSessionDescriptor).first
861	
862	        return LocalDataInventory(
863	            sleepSessionCount: sessions.count,
864	            baselineCount: try modelContext.fetchCount(FetchDescriptor<StoredBaseline>()),
865	            alertCount: try modelContext.fetchCount(FetchDescriptor<StoredAlert>()),
866	            protocolAdherenceCount: try modelContext.fetchCount(FetchDescriptor<StoredProtocolAdherence>()),
867	            activityLogCount: try modelContext.fetchCount(FetchDescriptor<StoredActivityStatusLog>()),
868	            manualBiologyEntryCount: try modelContext.fetchCount(FetchDescriptor<StoredManualBiologyEntry>()),
869	            sleepModeSettingsCount: try modelContext.fetchCount(FetchDescriptor<StoredSleepModeSettings>()),
870	            sleepModeScheduleCount: try modelContext.fetchCount(FetchDescriptor<StoredSleepModeSchedule>()),
871	            sleepModeSessionCount: try modelContext.fetchCount(FetchDescriptor<StoredSleepModeSession>()),
872	            contextEntryCount: contextCount,
873	            lastContextEntryDate: latestContextEntry?.updatedAt,
874	            lastSleepModeSessionDate: latestSleepModeSession?.startedAt,
875	            oldestSessionDate: sessions.first?.startDate,
876	            newestSessionDate: sessions.last?.startDate,
877	            protocolFormulaVersionCount: try modelContext.fetchCount(FetchDescriptor<StoredProtocolFormulaVersion>()),
878	            protocolNightLogCount: try modelContext.fetchCount(FetchDescriptor<StoredProtocolNightLog>()),
879	            protocolLogEditCount: try modelContext.fetchCount(FetchDescriptor<StoredProtocolLogEdit>()),
880	            protocolBaselineSnapshotCount: try modelContext.fetchCount(FetchDescriptor<StoredProtocolBaselineSnapshot>())
881	        )
882	    }
883	}
