166	private func gregorian() -> Calendar {
167	    var c = Calendar(identifier: .gregorian)
168	    c.timeZone = TimeZone(identifier: "UTC")!
169	    return c
170	}
171	
172	private func date(_ y: Int, _ m: Int, _ d: Int, hour: Int = 12, tz: TimeZone = .current) -> Date {
173	    var cal = Calendar(identifier: .gregorian)
174	    cal.timeZone = tz
175	    return cal.date(from: DateComponents(year: y, month: m, day: d, hour: hour))!
176	}
