178	/// Builds a SleepSession whose mutable stored properties match the requested metric values.
179	/// `restorativeSleepDuration` is computed as `deepDuration + remDuration` — so pass half
180	/// each into `deepSeconds`/`remSeconds` to get the desired restorative total.
181	private func makeSession(
182	    dateKey: String,
183	    quality: SleepDataQuality = .detailedStages,
184	    deepSeconds: Double = 2400,   // restorative = deep + rem; default → 4800 total
185	    remSeconds: Double = 2400,
186	    awakeSeconds: Double = 600,
187	    totalSleepSeconds: Double = 25200,
188	    latencySeconds: Double = 900,
189	    score: Double = 75.0
190	) -> SleepSession {
191	    // Parse YYYY-MM-DD → a fixed 23:00 start / 07:00 wake so the dateKey is correct.
192	    let parts = dateKey.split(separator: "-").compactMap { Int($0) }
193	    var cal = Calendar(identifier: .gregorian)
194	    cal.timeZone = .current
195	    let wake = cal.date(from: DateComponents(
196	        year: parts[0], month: parts[1], day: parts[2], hour: 7))!
197	    let start = wake.addingTimeInterval(-8 * 3600)
198	
199	    return SleepSession(
200	        sleepDateKey: dateKey,
201	        startDate: start,
202	        endDate: wake,
203	        dataQuality: quality,
204	        totalInBedTime: totalSleepSeconds + awakeSeconds,
205	        totalSleepTime: totalSleepSeconds,
206	        awakeDuration: awakeSeconds,
207	        deepDuration: deepSeconds,
208	        remDuration: remSeconds,
209	        sleepLatency: latencySeconds,
210	        qualityScore: SleepQualityScore(
211	            overall: score, durationScore: 0.75, efficiencyScore: 0.88,
212	            remScore: 0.75, deepScore: 0.75, isPartial: false)
213	    )
214	}
