264	    func testCalendarDateKeyIsGregorianUnderBuddhistLocale() {
265	        // Buddhist calendar year for 2026 would be 2569 if we used locale's preferred calendar.
266	        // We must always return the Gregorian key.
267	        var buddhistCal = Calendar(identifier: .buddhist)
