272	        let key = SleepDateKey.calendarDateKey(for: d, calendar: buddhistCal)
273	        XCTAssertEqual(key, "2026-05-21", "Buddhist calendar locale must not affect date key year")
274	    }
275	
276	    func testSleepDateKeySessionStartNoon_mapsToNextDay() {
277	        var cal = Calendar(identifier: .gregorian)
278	        cal.timeZone = TimeZone(identifier: "UTC")!
279	        let noon = date(2026, 5, 21, hour: 12, tz: cal.timeZone)
280	        let key = SleepDateKey.sleepDateKey(forSessionStart: noon, calendar: cal)
281	        XCTAssertEqual(key, "2026-05-22", "Session starting at noon → next day's key")
282	    }
