296	        let key = ProtocolFormulaHomeViewModel.tonightSleepDateKey(calendar: cal, now: twoAM)
297	        XCTAssertEqual(key, "2026-05-21", "Before 4am → tonight is today's key (night-in-progress)")
298	    }
299	
300	    func testTonightKeyBetween4amAnd12pm_routesToTomorrow() {
301	        // Regression for B3: before this fix, 9am returned today's key,
302	        // overwriting last night's log when "Mark Tonight Taken" was tapped.
303	        var cal = Calendar(identifier: .gregorian)
304	        cal.timeZone = TimeZone(identifier: "UTC")!
305	        for hour in [4, 7, 9, 11] {
