313	    func testTonightKeyAfter12pm_returnsNextDay() {
314	        var cal = Calendar(identifier: .gregorian)
315	        cal.timeZone = TimeZone(identifier: "UTC")!
316	        let eve = date(2026, 5, 21, hour: 21, tz: cal.timeZone)
317	        let key = ProtocolFormulaHomeViewModel.tonightSleepDateKey(calendar: cal, now: eve)
318	        XCTAssertEqual(key, "2026-05-22", "After 12pm → upcoming sleep night = tomorrow's key")
319	    }
320	
321	    func testTonightKeyNoCollisionWithLastNightKey() {
322	        // The tonight key should never equal the most-recent historical session key
323	        // during the "morning overlap" window (4–12h).
324	        var cal = Calendar(identifier: .gregorian)
325	        cal.timeZone = TimeZone(identifier: "UTC")!
326	        // Simulate: last night's session has sleepDateKey = "2026-05-21"
327	        let lastNightKey = "2026-05-21"
328	        let nineAM = date(2026, 5, 21, hour: 9, tz: cal.timeZone)
329	        let tonightKey = ProtocolFormulaHomeViewModel.tonightSleepDateKey(calendar: cal, now: nineAM)
330	        XCTAssertNotEqual(tonightKey, lastNightKey, "Tonight key must not collide with last night at 9am")
331	    }
332	
333	    func testDateKeyRoundTrip() {
334	        let d = date(2026, 12, 31, hour: 12, tz: TimeZone(identifier: "UTC")!)
335	        let key = SleepDateKey.calendarDateKey(for: d)
336	        let reconstructed = SleepDateKey.date(from: key)
337	        XCTAssertNotNil(reconstructed)
338	        // Reconstructed date should represent the same calendar day (y/m/d)
339	        let cal = Calendar(identifier: .gregorian)
340	        XCTAssertEqual(cal.component(.year, from: reconstructed!), 2026)
341	        XCTAssertEqual(cal.component(.month, from: reconstructed!), 12)
342	        XCTAssertEqual(cal.component(.day, from: reconstructed!), 31)
343	    }
