            meanRestorativeMin: nil, stdRestorativeMin: nil,
            meanRestorativePctOfInBed: 68, stdRestorativePctOfInBed: nil,   // delta = +6
            meanLongestRestorativeBlockMin: nil, stdLongestRestorativeBlockMin: nil,
