private extension LocalDataRepository {
    func deleteExistingSession(matching session: SleepSession) throws {
        let id = session.id
        let sleepDateKey = session.sleepDateKey
        let descriptor = FetchDescriptor<StoredSleepSession>(
            predicate: #Predicate { storedSession in
                storedSession.id == id || storedSession.sleepDateKey == sleepDateKey
            }
        )

        for storedSession in try modelContext.fetch(descriptor) {
            modelContext.delete(storedSession)
        }
    }

    nonisolated static func dateKey(for date: Date) -> String {
        var calendar = Calendar(identifier: .gregorian)
        calendar.timeZone = .current
        let components = calendar.dateComponents([.year, .month, .day], from: date)
        return String(
            format: "%04d-%02d-%02d",
            components.year ?? 0,
            components.month ?? 0,
            components.day ?? 0
        )
    }
}

// MARK: - Intervention window (V3)

/// Bounded period during which a `ProtocolFormulaVersion` was the active intervention.
/// One window per version. Closed when the next version ships (`endedAt = next.shippedOn`)
/// or when the version is archived (`endedAt = archivedAt`). Active version's window has
/// `endedAt = nil`. Used for sleep-data attribution and effect-size analysis.
nonisolated struct InterventionWindow: Codable, Hashable, Sendable, Identifiable {
    enum Phase: String, Codable, Hashable, Sendable, CaseIterable {
        /// Version is currently active (`endedAt == nil`).
        case active
        /// Closed because a newer version shipped.
        case superseded
        /// Closed because the version was archived without a successor.
        case archived
    }

    var id: UUID
    var versionID: UUID
    var startedAt: Date
    var endedAt: Date?
    var phase: Phase
    var createdAt: Date
    var updatedAt: Date

    init(
        id: UUID = UUID(),
        versionID: UUID,
        startedAt: Date,
        endedAt: Date? = nil,
        phase: Phase = .active,
        createdAt: Date = Date(),
        updatedAt: Date = Date()
    ) {
        self.id = id
        self.versionID = versionID
        self.startedAt = startedAt
        self.endedAt = endedAt
        self.phase = phase
        self.createdAt = createdAt
        self.updatedAt = updatedAt
    }

    /// Inclusive-start, exclusive-end check against a sleep date.
    func contains(_ date: Date) -> Bool {
        guard date >= startedAt else { return false }
        if let endedAt { return date < endedAt }
        return true
    }
}

