        ),
        ProtocolFormulaCatalogSpec(
            id: staticUUID("BEEF0004-0000-4000-8000-000000000004"),
            label: "V4",
            order: 4,
            formulaText: "V3 - L-theanine + Lemon balm 600mg",
            colorHex: "#67E8F9"
