9	import XCTest
10	@testable import Better
11	
12	// MARK: - In-memory repository for Protocol Formula tests
13	
14	/// Fully self-contained in-memory actor implementing `LocalDataRepositoryProtocol`.
15	/// All non-formula methods are no-ops or return empty — only the Protocol Formula
16	/// and SleepSession paths have real storage (needed by the baseline/analysis services).
17	private actor ProtocolFormulaMemoryRepo: LocalDataRepositoryProtocol {
18	    enum TestError: Error {
19	        case forcedNightLogSaveFailure
20	    }
21	
22	    // Session store (used by ProtocolBaselineService / ProtocolFormulaAnalysisService)
23	    private var sessionsByKey: [String: SleepSession]
24	
25	    // Protocol formula store
26	    var formulaVersions: [UUID: ProtocolFormulaVersion] = [:]
27	    var nightLogs: [String: ProtocolNightLog] = [:]
28	    var logEdits: [String: [ProtocolLogEdit]] = [:]
29	    var baseline: ProtocolBaselineSnapshot?
30	    private var failingNightLogSaveCount: Int = 0
31	
32	    // Legacy adherence (used by ProtocolAdherenceMigrationService.runIfNeeded)
33	    private var adherenceRows: [ProtocolAdherence] = []
34	
35	    init(sessions: [SleepSession] = [], adherence: [ProtocolAdherence] = []) {
36	        self.sessionsByKey = Dictionary(sessions.map { ($0.sleepDateKey, $0) },
37	                                       uniquingKeysWith: { _, new in new })
38	        self.adherenceRows = adherence
39	    }
40	
41	    // MARK: - Sessions
42	    func saveSessions(_ s: [SleepSession]) async throws {
43	        for session in s { sessionsByKey[session.sleepDateKey] = session }
44	    }
45	    func replaceSessions(_ s: [SleepSession], from: Date, to: Date) async throws {
46	        sessionsByKey = sessionsByKey.filter { $0.value.startDate < from || $0.value.endDate > to }
47	        try await saveSessions(s)
48	    }
49	    func fetchCachedSessions(from: Date, to: Date) async throws -> [SleepSession] {
50	        sessionsByKey.values.filter { $0.startDate >= from && $0.endDate <= to }
51	            .sorted { $0.startDate < $1.startDate }
52	    }
53	    func fetchSession(forSleepDateKey key: String) async throws -> SleepSession? { sessionsByKey[key] }
54	    func fetchSessions(beforeSleepDateKey key: String, limit: Int) async throws -> [SleepSession] {
