    func failNextNightLogSave() {
        failingNightLogSaveCount += 1
    }

    func saveNightLog(_ log: ProtocolNightLog) async throws {
        if failingNightLogSaveCount > 0 {
            failingNightLogSaveCount -= 1
            throw TestError.forcedNightLogSaveFailure
