        let sessions = (1...10).map { makeSession(dateKey: "2026-03-\(String(format: "%02d", $0))") }
        let repo = ProtocolFormulaMemoryRepo(sessions: sessions)
        let svc = ProtocolBaselineService(repository: repo, calendar: gregorian())
